export const sha256Js: string = "/**\r\n * soctiv-tracking — SHA-256 helper (browser)\r\n * Uses SubtleCrypto when available; falls back to a tiny pure-JS SHA-256\r\n * so the module never throws on older browsers / insecure contexts.\r\n *\r\n * Public API:\r\n *   window.SOCTIV.sha256(string) -> Promise<string>   (lowercase hex)\r\n *   window.SOCTIV.hashPII(obj)    -> Promise<object>  (hashes known PII keys)\r\n */\r\n(function () {\r\n  'use strict';\r\n\r\n  // Keys Meta expects to receive pre-hashed (lowercase, trimmed before hashing).\r\n  // Anything outside this list is passed through unchanged.\r\n  var PII_KEYS = ['em', 'ph', 'fn', 'ln', 'ct', 'st', 'zp', 'country', 'external_id'];\r\n\r\n  // -------- Pure-JS SHA-256 (fallback) --------\r\n  // Adapted from the well-known public-domain implementation. Used only when\r\n  // SubtleCrypto is unavailable (older browsers, http:// previews, etc.).\r\n  function sha256Sync(message) {\r\n    var K = [\r\n      0x428a2f98, 0x71374491, 0xb5c0fbcf, 0xe9b5dba5, 0x3956c25b, 0x59f111f1, 0x923f82a4, 0xab1c5ed5,\r\n      0xd807aa98, 0x12835b01, 0x243185be, 0x550c7dc3, 0x72be5d74, 0x80deb1fe, 0x9bdc06a7, 0xc19bf174,\r\n      0xe49b69c1, 0xefbe4786, 0x0fc19dc6, 0x240ca1cc, 0x2de92c6f, 0x4a7484aa, 0x5cb0a9dc, 0x76f988da,\r\n      0x983e5152, 0xa831c66d, 0xb00327c8, 0xbf597fc7, 0xc6e00bf3, 0xd5a79147, 0x06ca6351, 0x14292967,\r\n      0x27b70a85, 0x2e1b2138, 0x4d2c6dfc, 0x53380d13, 0x650a7354, 0x766a0abb, 0x81c2c92e, 0x92722c85,\r\n      0xa2bfe8a1, 0xa81a664b, 0xc24b8b70, 0xc76c51a3, 0xd192e819, 0xd6990624, 0xf40e3585, 0x106aa070,\r\n      0x19a4c116, 0x1e376c08, 0x2748774c, 0x34b0bcb5, 0x391c0cb3, 0x4ed8aa4a, 0x5b9cca4f, 0x682e6ff3,\r\n      0x748f82ee, 0x78a5636f, 0x84c87814, 0x8cc70208, 0x90befffa, 0xa4506ceb, 0xbef9a3f7, 0xc67178f2\r\n    ];\r\n    var H = [\r\n      0x6a09e667, 0xbb67ae85, 0x3c6ef372, 0xa54ff53a, 0x510e527f, 0x9b05688c, 0x1f83d9ab, 0x5be0cd19\r\n    ];\r\n\r\n    function rotr(n, x) { return (x >>> n) | (x << (32 - n)); }\r\n    function toBytes(str) {\r\n      var bytes = [];\r\n      for (var i = 0; i < str.length; i++) {\r\n        var c = str.charCodeAt(i);\r\n        if (c < 0x80) bytes.push(c);\r\n        else if (c < 0x800) { bytes.push(0xc0 | (c >> 6)); bytes.push(0x80 | (c & 0x3f)); }\r\n        else { bytes.push(0xe0 | (c >> 12)); bytes.push(0x80 | ((c >> 6) & 0x3f)); bytes.push(0x80 | (c & 0x3f)); }\r\n      }\r\n      return bytes;\r\n    }\r\n    function fromBytes(bytes) {\r\n      var hex = '';\r\n      for (var i = 0; i < bytes.length; i++) hex += (bytes[i] < 16 ? '0' : '') + bytes[i].toString(16);\r\n      return hex;\r\n    }\r\n\r\n    var bytes = toBytes(message);\r\n    var l = bytes.length;\r\n    bytes.push(0x80);\r\n    while (bytes.length % 64 !== 56) bytes.push(0);\r\n    var bitLen = l * 8;\r\n    for (var i = 7; i >= 0; i--) bytes.push((bitLen >>> (i * 8)) & 0xff);\r\n\r\n    var w = new Array(64);\r\n    for (var block = 0; block < bytes.length; block += 64) {\r\n      for (var t = 0; t < 16; t++) {\r\n        w[t] = (bytes[block + t * 4] << 24) | (bytes[block + t * 4 + 1] << 16) |\r\n               (bytes[block + t * 4 + 2] << 8) | bytes[block + t * 4 + 3];\r\n      }\r\n      for (var t2 = 16; t2 < 64; t2++) {\r\n        var s0 = rotr(7, w[t2 - 15]) ^ rotr(18, w[t2 - 15]) ^ (w[t2 - 15] >>> 3);\r\n        var s1 = rotr(17, w[t2 - 2]) ^ rotr(19, w[t2 - 2]) ^ (w[t2 - 2] >>> 10);\r\n        w[t2] = (w[t2 - 16] + s0 + w[t2 - 7] + s1) | 0;\r\n      }\r\n      var a = H[0], b = H[1], c = H[2], d = H[3], e = H[4], f = H[5], g = H[6], h = H[7];\r\n      for (var t3 = 0; t3 < 64; t3++) {\r\n        var S1 = rotr(6, e) ^ rotr(11, e) ^ rotr(25, e);\r\n        var ch = (e & f) ^ (~e & g);\r\n        var temp1 = (h + S1 + ch + K[t3] + w[t3]) | 0;\r\n        var S0 = rotr(2, a) ^ rotr(13, a) ^ rotr(22, a);\r\n        var mj = (a & b) ^ (a & c) ^ (b & c);\r\n        var temp2 = (S0 + mj) | 0;\r\n        h = g; g = f; f = e; e = (d + temp1) | 0;\r\n        d = c; c = b; b = a; a = (temp1 + temp2) | 0;\r\n      }\r\n      H[0] = (H[0] + a) | 0; H[1] = (H[1] + b) | 0; H[2] = (H[2] + c) | 0; H[3] = (H[3] + d) | 0;\r\n      H[4] = (H[4] + e) | 0; H[5] = (H[5] + f) | 0; H[6] = (H[6] + g) | 0; H[7] = (H[7] + h) | 0;\r\n    }\r\n    return fromBytes(H.map(function (n) {\r\n      return [(n >>> 24) & 0xff, (n >>> 16) & 0xff, (n >>> 8) & 0xff, n & 0xff];\r\n    }).reduce(function (a, b) { return a.concat(b); }, []));\r\n  }\r\n\r\n  function normalize(value) {\r\n    return String(value == null ? '' : value).trim().toLowerCase();\r\n  }\r\n\r\n  function hash(value) {\r\n    var v = normalize(value);\r\n    if (!v) return Promise.resolve('');\r\n    if (window.crypto && window.crypto.subtle && window.crypto.subtle.digest) {\r\n      var enc = new TextEncoder();\r\n      return window.crypto.subtle.digest('SHA-256', enc.encode(v)).then(function (buf) {\r\n        var bytes = new Uint8Array(buf);\r\n        var hex = '';\r\n        for (var i = 0; i < bytes.length; i++) hex += (bytes[i] < 16 ? '0' : '') + bytes[i].toString(16);\r\n        return hex;\r\n      });\r\n    }\r\n    return Promise.resolve(sha256Sync(v));\r\n  }\r\n\r\n  function hashPII(obj) {\r\n    obj = obj || {};\r\n    var out = {};\r\n    var promises = [];\r\n    Object.keys(obj).forEach(function (key) {\r\n      var val = obj[key];\r\n      if (val == null || val === '') {\r\n        out[key] = '';\r\n        return;\r\n      }\r\n      if (PII_KEYS.indexOf(key) !== -1) {\r\n        promises.push(hash(val).then(function (h) { out[key] = h; }));\r\n      } else {\r\n        out[key] = val;\r\n      }\r\n    });\r\n    return Promise.all(promises).then(function () { return out; });\r\n  }\r\n\r\n  window.SOCTIV = window.SOCTIV || {};\r\n  window.SOCTIV.sha256 = hash;\r\n  window.SOCTIV.hashPII = hashPII;\r\n})();\r\n";

export const headersFile: string = "# Security + performance headers for the PUBLISHED Soctiv landing pages.\r\n#\r\n# This file is shipped by the `publish-landing-page` edge function into every\r\n# per-page deploy on Netlify (the user-facing `<brand>.soctiv.ly` pages, NOT\r\n# the React dashboard at soctivcrm.com). Without these headers a stored-XSS\r\n# regression in the templating engine (see SECURITY.md) would have no defense\r\n# in depth.\r\n#\r\n# Tight CSP: the only third-party origins we ever need are:\r\n#   - fonts.googleapis.com / fonts.gstatic.com for the user-picked Google Font\r\n#   - connect.facebook.net for Meta Pixel (loaded by assets/pixel.js)\r\n#   - www.facebook.com for Meta CAPI + Pixel match (Pixel advanced matching)\r\n#   - www.googletagmanager.com / www.google-analytics.com for GTM/GA\r\n#     (in case the user picks them in a future analytics plugin)\r\n#   - *.supabase.co for webhook + CAPI proxy calls (the published page POSTs\r\n#     to <project>.supabase.co/functions/v1/facebook-leads-webhook and\r\n#     /functions/v1/capi-proxy)\r\n#   - api.netlify.com is not contacted by the page itself, only by the edge\r\n#     function during publish — no need to list it here.\r\n#\r\n# We disallow inline scripts (no 'unsafe-inline'), `object-src 'none'`, and\r\n# `frame-ancestors 'none'` so the page can never be embedded in an iframe\r\n# (clickjacking protection). 'strict-dynamic' is intentionally omitted — it\r\n# would allow nonced scripts to load arbitrary origins, defeating the point.\r\n\r\n/*\r\n  X-Content-Type-Options: nosniff\r\n  X-Frame-Options: DENY\r\n  Referrer-Policy: strict-origin-when-cross-origin\r\n  Strict-Transport-Security: max-age=63072000; includeSubDomains; preload\r\n  Permissions-Policy: camera=(), microphone=(), geolocation=(), payment=()\r\n  Content-Security-Policy: default-src 'self'; script-src 'self' https://connect.facebook.net https://www.facebook.com https://www.googletagmanager.com https://www.google-analytics.com; style-src 'self' 'unsafe-inline' https://fonts.googleapis.com; font-src 'self' https://fonts.gstatic.com; img-src 'self' data: https:; connect-src 'self' https://*.supabase.co https://www.facebook.com https://www.google-analytics.com; frame-src 'self' https://www.facebook.com; object-src 'none'; base-uri 'self'; frame-ancestors 'none'; form-action 'self' https://*.supabase.co\r\n\r\n/*.html\r\n  Cache-Control: public, max-age=300, s-maxage=300, stale-while-revalidate=86400\r\n\r\n/assets/*\r\n  Cache-Control: public, max-age=31536000, immutable\r\n\r\n/*.css\r\n  Cache-Control: public, max-age=31536000, immutable\r\n\r\n/*.js\r\n  Cache-Control: public, max-age=31536000, immutable\r\n";

export const edgeFn_dir: string = "netlify/edge-functions";
export const edgeFn_subdomain_router_file: string = "subdomain-router.ts";
export const edgeFn_subdomain_router_body: string = "//\n// Reads the request's Host header and rewrites any *.soctiv.ly subdomain\n// request to the matching landing page directory.\n//\n// Why this exists: Netlify's _redirects file does NOT reliably match\n// full-URL `from` patterns on Netlify's CDN edge the way the docs imply,\n// so per-host routing can't be done with plain static rules. Edge\n// Functions run before static-file serving and before _redirects, so\n// they are the canonical place to do Host-header-based rewrites.\n//\n// Map source: `/_subdomain_map.json` (written by the publish-landing-page\n// Supabase edge function on every publish). Example file:\n//   { \"generated_at\": \"...\", \"map\": { \"test\": \"<pageId>\", \"acme\": \"<pageId>\" } }\n//\n// Behavior:\n//   1. If Host ends in `.soctiv.ly` (but is NOT `soctiv.ly` or `www.soctiv.ly`):\n//        - extract the subdomain\n//        - look up the pageId in the map (cached per isolate)\n//        - rewrite URL to `/<pageId>/<original-path>`\n//   2. Otherwise: return the response unchanged (falls through to the\n//      SPA / static files / _redirects as normal).\n//\n// Cache strategy:\n//   - The map is fetched from Netlify's CDN with `Cache-Control: public,\n//     max-age=30` semantics (handled implicitly by the static-file cache\n//     for an asset under the site's own deploy). A 30s window is short\n//     enough that a publish is reflected within ~30s globally without\n//     invalidating the CDN cache by hand.\n//   - To force a faster pickup after a publish, the publish function\n//     appends a `?v=<deploy-id>` query string on first load (the URL is\n//     not visible to end users because the edge function rewrites\n//     before serving).\n//\n// Deployed as part of every publish — the Supabase function tars the\n// `netlify/edge-functions/` directory into the deploy automatically.\n//\n// NOTE: This runs on Deno at Netlify's edge. The standard library import\n// `https://deno.land/std@0.224.0/http/server.ts` is intentionally avoided\n// to keep cold-start latency minimal — only `Deno` globals are used.\n\nimport type { Context } from \"https://edge.netlify.com\";\n\ninterface SubdomainMap {\n  generated_at?: string;\n  map: Record<string, string>;\n}\n\n// Per-isolate cache so a burst of requests for the same site doesn't\n// re-fetch the map on every request.\nlet cachedMap: SubdomainMap | null = null;\nlet cachedMapAt = 0;\nconst MAP_TTL_MS = 30_000;\n\nconst SOCTIV_BASE = \"soctiv.ly\";\nconst RESERVED_SUBDOMAINS = new Set([\"\", \"www\"]);\n\nasync function loadMap(origin: string): Promise<SubdomainMap | null> {\n  const now = Date.now();\n  if (cachedMap && now - cachedMapAt < MAP_TTL_MS) return cachedMap;\n  try {\n    const res = await fetch(`${origin}/_subdomain_map.json`, {\n      headers: { \"accept\": \"application/json\" },\n    });\n    if (!res.ok) return cachedMap; // stale-while-revalidate: keep old map\n    cachedMap = (await res.json()) as SubdomainMap;\n    cachedMapAt = now;\n    return cachedMap;\n  } catch {\n    return cachedMap;\n  }\n}\n\nexport default async (request: Request, context: Context): Promise<Response> => {\n  const url = new URL(request.url);\n  const hostHeader = request.headers.get(\"host\") || url.host;\n  // Strip port if present (e.g. \"test.soctiv.ly:443\" → \"test.soctiv.ly\").\n  const host = hostHeader.split(\":\")[0].toLowerCase();\n\n  // Fast path: only act on *.soctiv.ly subdomains.\n  if (!host.endsWith(`.${SOCTIV_BASE}`)) {\n    return; // undefined → fall through to next handler / static serve\n  }\n  const sub = host.slice(0, host.length - SOCTIV_BASE.length - 1); // remove \".soctiv.ly\"\n  if (RESERVED_SUBDOMAINS.has(sub)) {\n    return; // soctiv.ly / www.soctiv.ly — fall through to the SPA\n  }\n\n  // Always serve from the same origin so the map lookup hits the local\n  // deploy (no CORS, no cross-site auth).\n  const origin = url.origin;\n  const map = await loadMap(origin);\n  const pageId = map?.map?.[sub];\n  if (!pageId) {\n    // Unknown subdomain — return a clean 404 so the user doesn't see the\n    // Netlify default 404 with site branding. Don't leak any info.\n    return new Response(\"Not Found\", {\n      status: 404,\n      headers: {\n        \"content-type\": \"text/plain; charset=utf-8\",\n        \"cache-control\": \"no-store\",\n      },\n    });\n  }\n\n  // Build the rewritten URL: /<pageId><original path>\n  // Use the original pathname + search so deep links survive.\n  const target = `/${pageId}${url.pathname === \"/\" ? \"/\" : url.pathname}${url.search}`;\n  const rewritten = new URL(target, origin);\n\n  // Clone the request with the rewritten URL so downstream handlers see\n  // the new path. Forward all headers (incl. cookies, range, etc.).\n  const newRequest = new Request(rewritten.toString(), {\n    method: request.method,\n    headers: request.headers,\n    body: request.body,\n    redirect: \"manual\",\n  });\n\n  // context.next() runs the rest of the request lifecycle (static file\n  // serve, _redirects, etc.) with the rewritten URL.\n  const response = await context.next({ request: newRequest });\n  // Add a debug header so we can confirm the edge function fired in\n  // production. Cheap, doesn't break anything.\n  response.headers.set(\"x-soctiv-router\", `sub=${sub};page=${pageId}`);\n  return response;\n};\n\nexport const config = {\n  // Run on every path. The function itself decides whether to act based\n  // on Host, so we don't need to filter by path here.\n  path: \"/*\",\n};\n";

